INSERT INTO extracted_studies (ref_no,first_author,authors_full,year,title,venue,country,pathology,pathology_code,modality,dataset_name,dataset_access,patient_count,image_count,task,model,method_detail,summary,performance,ext_validation,radiologist_comparison,open_code,open_data,code_url,depth,limitations,doi_url) VALUES (12,'Lilhore U.K.','Lilhore Umesh Kumar; Sanaj M. S.; Priya K. V.; Rasmi A.; Sharma Rahul; Tekeste Lidia Gosy; Ghith Ehab Seif; Hussien Shimaa A.; Simaiya Sarita',2026,'Hybrid Quantum-Inspired Transformer Network for Kidney Stone Prediction Using Urine Analysis and CT Scans','International Journal of Computational Intelligence Systems',NULL,'Ürolitiyazis/Nefrolitiyazis','URO','BT/CTA',NULL,'Belirtilmemiş',NULL,NULL,'multimodal taş varlığı tahmini ve sınıflandırma','HQIT-Net; quantum-inspired CNN, Vision Transformer, Bi-LSTM + attention ve multimodal füzyon','HQIT-Net, CT görüntülerinden görsel özellikleri ViT/quantum-inspired CNN ile; idrar değişkenlerinden sayısal örüntüleri Bi-LSTM + attention ile çıkarır ve bu temsilleri multimodal füzyonla birleştirir.','HQIT-Net, böbrek taşı tahmini için CT görüntüleri ile idrar biyokimyası verilerini birleştiren deneysel multimodal bir derin öğrenme modelidir.','{"AUC": "0.998", "ACC": "0.991", "SEN": "0.986", "SPE": "0.993", "F1": "0.989"}','Yok','Yok','Yok','Yok',NULL,'Manuel ayrıntılı inceleme','of Existing Diagnostic Methods Traditional assessment tools for nephrolithiasis are urine microscopy, biochemical urine tests and imaging (e.g. ultrasound, computed tomography [CT], X-ray) [10, 11]. While such methods provide valuable diagnostic indications, they exhibit several important shortcomings: ● High expense and radiation: CT scans are the','https://doi.org/10.1007/s44196-025-01138-2');
