INSERT INTO extracted_studies (ref_no,first_author,authors_full,year,title,venue,country,pathology,pathology_code,modality,dataset_name,dataset_access,patient_count,image_count,task,model,method_detail,summary,performance,ext_validation,radiologist_comparison,open_code,open_data,code_url,depth,limitations,doi_url) VALUES (30,'Alshenaifi R','Alshenaifi R.; Alqahtani Y.; Mohamed Aslam S.; Umapathy S.',2025,'AI-driven framework for automated detection of kidney stones in CT images: integration of deep learning architectures and transformers','Biomedical Physics and Engineering Express, 11(5)','India','Ürolitiyazis/Nefrolitiyazis','URO','BT/CTA',NULL,'Halka açık',500,1799,'segmentasyon, sınıflandırma, tespit','Vision Transformer ailesi | özgül mimari/karşılaştırılan modeller: ViT','Çalışma BT üzerinden segmentasyon, sınıflandırma, tespit amacına yöneliktir. Yöntem ailesi: Vision Transformer ailesi | özgül mimari/karşılaştırılan modeller: ViT. Bu yorum özet/metadata düzeyindedir. Modelin klinik rolü, görüntü veya klinik/radyomik özelliklerden otomatik karar desteği üretmek olarak kodlandı.','Alshenaifi R ve ark. (2025) Üriner sistem taşı / nefrolitiazis alanında BT kullanarak segmentasyon, sınıflandırma, tespit için Vision Transformer ailesi | özgül mimari/karşılaştırılan modeller: ViT yaklaşımını değerlendirmiştir. Bu kayıt özet/metadata düzeyinde incelenmiştir. Raporlanan başlıca performans metrikleri: Doğruluk: 0.973.','{"ACC": "0.9727", "SEN": "0.977", "DICE": "0.803", "IOU": "0.671"}','Yok','Yok','Yok','Yok',NULL,'Özet/metadata','in handling diverse clinical conditions or datasets with extreme noise and variability, emphasizing the need for further validation in real-world scenarios. S Asif et al proposed a model called StoneNet based on MobileNet with minimizing the number of parameters.','https://iopscience.iop.org/article/10.1088/2057-1976/adf3ba');
INSERT INTO extracted_studies (ref_no,first_author,authors_full,year,title,venue,country,pathology,pathology_code,modality,dataset_name,dataset_access,patient_count,image_count,task,model,method_detail,summary,performance,ext_validation,radiologist_comparison,open_code,open_data,code_url,depth,limitations,doi_url) VALUES (31,'Alzughaibi A.','Alzughaibi A.; Alanazi A. A.; Alshahrani M.; Hilali Jaghdam I.; Hassaballa A. A.',2025,'Synergizing vision transformer with ensemble of deep learning model for accurate kidney stone detection using CT imaging','Alexandria Engineering Journal, 127, 357-373','Saudi Arabia','Ürolitiyazis/Nefrolitiyazis','URO','BT/CTA',NULL,'Belirtilmemiş',NULL,NULL,'tespit','Vision Transformer ailesi | özgül mimari/karşılaştırılan modeller: swin; swin transformer','Çalışma BT üzerinden tespit amacına yöneliktir. Yöntem ailesi: Vision Transformer ailesi | özgül mimari/karşılaştırılan modeller: swin; swin transformer. Bu yorum özet/metadata düzeyindedir. Modelin klinik rolü, görüntü veya klinik/radyomik özelliklerden otomatik karar desteği üretmek olarak kodlandı.','Alzughaibi A. ve ark. (2025) Üriner sistem taşı / nefrolitiazis alanında BT kullanarak tespit için Vision Transformer ailesi | özgül mimari/karşılaştırılan modeller: swin; swin transformer yaklaşımını değerlendirmiştir. Bu kayıt özet/metadata düzeyinde incelenmiştir. Performans değeri yapılandırılmış alanda veya otomatik tam metin taramasında net yakalanamadı; manuel kontrol gerekir.','{"ACC": "0.9897", "F1": "0.9874"}','Yok','Yok','Yok','Yok',NULL,'Özet/metadata','persist in current research. Many studies primarily concentrate on individual DL methods, such as CNNs or pretrained models, without thoroughly integrating diverse architectures for more robust performance.','https://www.sciencedirect.com/science/article/pii/S1110016825006453?via%3Dihub');
