INSERT INTO extracted_studies (ref_no,first_author,authors_full,year,title,venue,country,pathology,pathology_code,modality,dataset_name,dataset_access,patient_count,image_count,task,model,method_detail,summary,performance,ext_validation,radiologist_comparison,open_code,open_data,code_url,depth,limitations,doi_url) VALUES (33,'S. Ding','Ding Shukai; Khamsemanan Nirattaya; Nattee Cholwich',2025,'SAM: A Lightweight Static Attention Module for Kidney Stone Detection in CT Images',NULL,'Thailand','Ürolitiyazis/Nefrolitiyazis','URO','BT/CTA',NULL,'Belirtilmemiş',NULL,1799,'tespit','Segment Anything Model ailesi, 2B evrişimsel sinir ağı | özgül mimari/karşılaştırılan modeller: ResNet50; SAM','Çalışma BT üzerinden tespit amacına yöneliktir. Yöntem ailesi: Segment Anything Model ailesi, 2B evrişimsel sinir ağı | özgül mimari/karşılaştırılan modeller: ResNet50; SAM. Bu yorum özet/metadata düzeyindedir. Modelin klinik rolü, görüntü veya klinik/radyomik özelliklerden otomatik karar desteği üretmek olarak kodlandı.','S. Ding ve ark. (2025) Üriner sistem taşı / nefrolitiazis alanında BT kullanarak tespit için Segment Anything Model ailesi, 2B evrişimsel sinir ağı | özgül mimari/karşılaştırılan modeller: ResNet50; SAM yaklaşımını değerlendirmiştir. Bu kayıt özet/metadata düzeyinde incelenmiştir. Performans değeri yapılandırılmış alanda veya otomatik tam metin taramasında net yakalanamadı; manuel kontrol gerekir.','{"ACC": "0.9942"}','Yok','Yok','Yok','Yok',NULL,'Özet/metadata','arise from two main causes. Transformer models need tens of thousands of training images to learn long-range relationships; Yildirim offers fewer than two thousand, so their self-attention layers underfit and miss tiny stones.','https://ieeexplore.ieee.org/document/11452121/');
