INSERT INTO extracted_studies (ref_no,first_author,authors_full,year,title,venue,country,pathology,pathology_code,modality,dataset_name,dataset_access,patient_count,image_count,task,model,method_detail,summary,performance,ext_validation,radiologist_comparison,open_code,open_data,code_url,depth,limitations,doi_url) VALUES (93,'Roby M','Roby Merjulah; Restrepo Juan C.; Shan Deepak K.; Muluk Satish C.; Eskandari Mark K.; Kashyap Vikram S.; Finol Ender A.',2026,'An Integrated Framework for Automated Image Segmentation and Personalized Wall Stress Estimation of Abdominal Aortic Aneurysms','Bioengineering','USA','Abdominal Aort Anevrizması/Diseksiyonu','AAA','Belirsiz',NULL,'Özel/tek merkez',NULL,9037,'segmentasyon, klinik sonuç veya risk tahmini','U-Net ailesi | özgül mimari/karşılaştırılan modeller: U-Net','Çalışma BT anjiyografi üzerinden segmentasyon, klinik sonuç veya risk tahmini amacına yöneliktir. Yöntem ailesi: U-Net ailesi | özgül mimari/karşılaştırılan modeller: U-Net. Bu yorum Chrome/web tam metnine dayalıdır. Modelin klinik rolü, görüntü veya klinik/radyomik özelliklerden otomatik karar desteği üretmek olarak kodlandı.','Roby M ve ark. (2026) Aort anevrizması / aort diseksiyonu alanında BT anjiyografi kullanarak segmentasyon, klinik sonuç veya risk tahmini için U-Net ailesi | özgül mimari/karşılaştırılan modeller: U-Net yaklaşımını değerlendirmiştir. Bu kayıt Chrome/web tam metin düzeyinde incelenmiştir. Performans değeri yapılandırılmış alanda veya otomatik tam metin taramasında net yakalanamadı; manuel kontrol gerekir. Nihai yayın olarak tutuldu; 83 numaralı aynı başlıklı preprint/tekrar kayıt bu kayda birleştirildi.','{"ACC": "0.998", "DICE": "0.916", "IOU": "0.941"}','Yok','Yok','Yok','Yok',NULL,'Web tam metin','of the aforementioned approaches, the need for automated segmentation tools for medical image analysis is warranted. Chandrashekar et al. [10] used deep learning to automatically segment aortic aneurysms in CTA images, achieving DSC (Dice Similarity Coefficient) scores of 0.887 ± 0.005 at low resolution and 0.932 ± 0.007 at high resolution.','https://www.mdpi.com/2306-5354/13/2/191');
