INSERT INTO extracted_studies (ref_no,first_author,authors_full,year,title,venue,country,pathology,pathology_code,modality,dataset_name,dataset_access,patient_count,image_count,task,model,method_detail,summary,performance,ext_validation,radiologist_comparison,open_code,open_data,code_url,depth,limitations,doi_url) VALUES (96,'Cai W.','Cai Wenjie; Liu Nianping; Zhang Hongjie; Zhai Jia; Wang Qingfeng; Zhou Ying Gang; Kong Lingming; Li Jing',2026,'FMTW-SAM: Foreground mixing and temporally weighted SAM feature fusion for cross-domain semi-supervised segmentation of type-B aortic dissection in computed tomography angiography','Neurocomputing','China','Abdominal Aort Anevrizması/Diseksiyonu','AAA','BT/CTA',NULL,'Çok merkezli',NULL,NULL,'true lumen / false lumen segmentasyonu','SAM ailesi, Mean Teacher, U-Net/ResU-Net ve foreground mixing stratejisi','Çalışma BT anjiyografi üzerinden segmentasyon amacına yöneliktir. Yöntem ailesi: Segment Anything Model ailesi | özgül mimari/karşılaştırılan modeller: SAM. Bu yorum özet/metadata düzeyindedir. Modelin klinik rolü, görüntü veya klinik/radyomik özelliklerden otomatik karar desteği üretmek olarak kodlandı.','FMTW-SAM, alanlar arası yarı gözetimli diseksiyon segmentasyonu için SAM özellik füzyonu ve foreground mixing kullanan bir yaklaşımdır.','{"DICE": "0.8272"}','Yok','Yok','Var','Var','https://github.com/Jieustc/FMTW-SAM','Manuel ayrıntılı inceleme','is evident in Table 2. For example, on TBAD-10, FMTW-SAM improves Dice-FL from 82.72% (ABD-CT) and 58.50% (DuCiSC) to 88.23%; on TBAD-20, it im­ proves Dice-FL from 88.10% (ABD-CT) and 86.97% (DuCiSC) to 91.20%.','https://doi.org/10.1016/j.neucom.2026.133758');
