INSERT INTO extracted_studies (ref_no,first_author,authors_full,year,title,venue,country,pathology,pathology_code,modality,dataset_name,dataset_access,patient_count,image_count,task,model,method_detail,summary,performance,ext_validation,radiologist_comparison,open_code,open_data,code_url,depth,limitations,doi_url) VALUES (106,'Hu Y','Hu Yujian; Xiang Yilang; Zhou Yan-Jie; He Yangyan; Lang Dehai; Yang Shifeng; Du Xiaolong; Den Chunlan; Xu Youyao; Wang Gaofeng; Ding Zhengyao; Huang Jingyong; Zhao Wen-Jun; Wu Xuejun; Li Donglin; Zhu Qianqian; Li Zhenjiang; Qiu Chenyang; Wu Ziheng; He Yunjun; Chen Tian; Qiu Yihui; Lin Zuodong; Zhang Xiaolong; Hu Lin; He Yuan; Yuan Zhenpeng; Zhou Xiaoxiang; Fan Rong; Chen Ruihan; Guo Wenchao; Xu Jing; Zhang Jianpeng; Mok Tony C. W.; Li Zi; Kalra Mannudeep K.; Lü Le; Xiao Wenbo; Li Xiaoqiang; Bian Yun; Shao Chengwei; Wang Guofu; Lu Wei; Huang Zhengxing; Xu Minfeng; Zhang Hongkun',2025,'AI-based diagnosis of acute aortic syndrome from noncontrast CT','Nature Medicine','China','Abdominal Aort Anevrizması/Diseksiyonu','AAA','BT/CTA',NULL,'Çok merkezli',15584,NULL,'kontrastsız BT''de AAS tespiti, hasta düzeyi sınıflandırma, lokalizasyon ve acil triyaj','iAorta; derin öğrenme tabanlı uyarı sistemi, aorta/true lumen segmentasyonu ve lezyon lokalizasyonu içeren sınıflandırma modeli','iAorta, kontrastsız BT''de AAS varlığını hasta düzeyinde saptar; aort ve true lumen segmentasyonu ile olası lezyon bölgelerini lokalize ederek yorumlanabilir uyarı üretir. CTA arteriyel faz tanısı ve lezyon anotasyonları kayıt/transfer yoluyla kontrastsız BT eğitimine gözetim sağlar.','iAorta, kontrastsız BT''de akut aort sendromunu erken saptamak ve CTA''ya yönlendirmeyi hızlandırmak için geliştirilmiş çok merkezli, prospektif pilotu olan bir derin öğrenme uyarı sistemidir.','{"AUC": "0.98", "SEN": "0.955", "SPE": "0.994"}','Var','Var','Yok','Yok',NULL,'PDF tam metin','of iAorta that are worth mentioning. First, our model was trained and validated on diverse cohorts within the Chinese population.','https://doi.org/10.1038/s41591-025-03916-z');
