INSERT INTO extracted_studies (ref_no,first_author,authors_full,year,title,venue,country,pathology,pathology_code,modality,dataset_name,dataset_access,patient_count,image_count,task,model,method_detail,summary,performance,ext_validation,radiologist_comparison,open_code,open_data,code_url,depth,limitations,doi_url) VALUES (128,'Katakol S','Katakol Sudeep; Baker Timothy J.; Bian Zhangxing; Lu Yanglong; Spahlinger Greg; Hatt Charles R.; Burris Nicholas S.',2023,'Fully automated pipeline for measurement of the thoracic aorta using joint segmentation and localization neural network','Journal of Medical Imaging','USA','Abdominal Aort Anevrizması/Diseksiyonu','AAA','Belirsiz',NULL,'Özel/tek merkez',67,60,'segmentasyon, lokalizasyon','evrişimsel sinir ağı','Çalışma BT anjiyografi üzerinden segmentasyon, lokalizasyon amacına yöneliktir. Yöntem ailesi: evrişimsel sinir ağı. Bu yorum Chrome/web sayfasından elde edilen özet/metadata düzeyindedir. Modelin klinik rolü, görüntü veya klinik/radyomik özelliklerden otomatik karar desteği üretmek olarak kodlandı.','Katakol S ve ark. (2023) Aort anevrizması / aort diseksiyonu alanında BT anjiyografi kullanarak segmentasyon, lokalizasyon için evrişimsel sinir ağı yaklaşımını değerlendirmiştir. Bu kayıt Chrome/web özet-metadata düzeyinde incelenmiştir. Performans değeri yapılandırılmış alanda veya otomatik tam metin taramasında net yakalanamadı; manuel kontrol gerekir.','{"DICE": "0.97"}','Yok','Yok','Var','Yok','https://github.com/Burris-Group/FullyAutomated-Aorta-Measurement-Pipeline','Web özet/metadata','of manual and prior automated approaches, we develop a machine learning (ML) based algorithm that allows us to obtain aortic measurements in a fully automated fashion. Our current method builds on recent work involving the use of convolutional neural networks (CNNs) to segment6,11,12 and localize key anatomic landmarks on the aorta.13 Specifically,','https://www.spiedigitallibrary.org/journals/journal-of-medical-imaging/volume-10/issue-05/051810/Fully-automated-pipeline-for-measurement-of-the-thoracic-aorta-using/10.1117/1.JMI.10.5.051810.full');
INSERT INTO extracted_studies (ref_no,first_author,authors_full,year,title,venue,country,pathology,pathology_code,modality,dataset_name,dataset_access,patient_count,image_count,task,model,method_detail,summary,performance,ext_validation,radiologist_comparison,open_code,open_data,code_url,depth,limitations,doi_url) VALUES (129,'Saitta S','Saitta S.; Sturla F.; Caimi A.; Riva A.; Palumbo M. C.; Nano G.; Votta E.; Corte ; A. della ; Glauber M.; Chiappino D.; Marrocco-Trischitta M. M.; Redaelli A.',2022,'A Deep Learning-Based and Fully Automated Pipeline for Thoracic Aorta Geometric Analysis and Planning for Endovascular Repair from Computed Tomography','Journal of Digital Imaging, 35(2), 226-239',NULL,'Abdominal Aort Anevrizması/Diseksiyonu','AAA','BT/CTA','Medical Segmentation Decathlon','Halka açık',NULL,465,'segmentasyon, tespit','U-Net ailesi | özgül mimari/karşılaştırılan modeller: 3D U-Net','Çalışma BT üzerinden segmentasyon, tespit amacına yöneliktir. Yöntem ailesi: U-Net ailesi | özgül mimari/karşılaştırılan modeller: 3D U-Net. Bu yorum PDF tam metnine dayalıdır. Modelin klinik rolü, görüntü veya klinik/radyomik özelliklerden otomatik karar desteği üretmek olarak kodlandı.','Saitta S ve ark. (2022) Aort anevrizması / aort diseksiyonu alanında BT kullanarak segmentasyon, tespit için U-Net ailesi | özgül mimari/karşılaştırılan modeller: 3D U-Net yaklaşımını değerlendirmiştir. Bu kayıt PDF tam metin düzeyinde incelenmiştir. Raporlanan başlıca performans metrikleri: Dice: 0.95.','{"DICE": "0.95"}','Yok','Yok','Yok','Yok',NULL,'PDF tam metin','Indeed, the CNN training, which requires a large number of CT scans, was performed on images of healthy subjects, and therefore our work must be conservatively regarded as a proof-of-concept study. Nevertheless, the CNN was successfully tested also for pathological CT scans, even though in a small group of aneurismatic patients.','https://doi.org/10.1007/s10278-021-00535-1');
