INSERT INTO extracted_studies (ref_no,first_author,authors_full,year,title,venue,country,pathology,pathology_code,modality,dataset_name,dataset_access,patient_count,image_count,task,model,method_detail,summary,performance,ext_validation,radiologist_comparison,open_code,open_data,code_url,depth,limitations,doi_url) VALUES (145,'Raj A','Raj A.; Allababidi A.; Kayed H.; Gerken A. L. H.; Muller J.; Schoenberg S. O.; Zollner F. G.; Rink J. S.',2024,'Streamlining Acute Abdominal Aortic Dissection Management-An AI-based CT Imaging Workflow','Journal of Imaging Informatics in Medicine, 37(6), 2729-2739',NULL,'Abdominal Aort Anevrizması/Diseksiyonu','AAA','BT/CTA','KiTS; TotalSegmentator; AbdomenCT','Çok merkezli',778,163,'sınıflandırma, tespit, klinik sonuç veya risk tahmini','evrişimsel sinir ağı','Çalışma BT üzerinden sınıflandırma, tespit, klinik sonuç veya risk tahmini amacına yöneliktir. Yöntem ailesi: evrişimsel sinir ağı. Bu yorum PDF tam metnine dayalıdır. Modelin klinik rolü, görüntü veya klinik/radyomik özelliklerden otomatik karar desteği üretmek olarak kodlandı.','Raj A ve ark. (2024) Aort anevrizması / aort diseksiyonu alanında BT kullanarak sınıflandırma, tespit, klinik sonuç veya risk tahmini için evrişimsel sinir ağı yaklaşımını değerlendirmiştir. Bu kayıt PDF tam metin düzeyinde incelenmiştir. Raporlanan başlıca performans metrikleri: doğruluk: 0.887; duyarlılık: 0.887.','{"AUC": "0.948", "ACC": "0.789", "SEN": "0.875", "SPE": "0.875"}','Var','Yok','Yok','Yok',NULL,'PDF tam metin','lies in the lack of external validation, raising concerns about the generalizability of their model. Huang et al. [16] proposed a 2-step hierarchical model involving an attention U-Net for initial AD detection (AD case; if 5 or more slices were detected with AD) followed by a ResNext model [17] for Stanford type classification.','https://doi.org/10.1007/s10278-024-01164-0');
INSERT INTO extracted_studies (ref_no,first_author,authors_full,year,title,venue,country,pathology,pathology_code,modality,dataset_name,dataset_access,patient_count,image_count,task,model,method_detail,summary,performance,ext_validation,radiologist_comparison,open_code,open_data,code_url,depth,limitations,doi_url) VALUES (146,'Cheng J','Cheng J.; Zhang Z.; Wang Y.; Sun Y.; Wang N.; Wang X.; Wang S.',2026,'Predicting the growth of asymptomatic small abdominal aortic aneurysms (AAA) based on deep learning','Frontiers in Physiology, 16','China','Abdominal Aort Anevrizması/Diseksiyonu','AAA','BT/CTA',NULL,'Çok merkezli',289,NULL,'hızlı büyüme tahmini','ResNet50, YOLOv11 ve klinik-görüntü füzyonlu MedMamba','Çalışma BT anjiyografi üzerinden sınıflandırma, tespit, klinik sonuç veya risk tahmini amacına yöneliktir. Yöntem ailesi: nesne tespit modeli, 2B evrişimsel sinir ağı | özgül mimari/karşılaştırılan modeller: ResNet50; YOLOv1. Bu yorum PDF tam metnine dayalıdır. Modelin klinik rolü, görüntü veya klinik/radyomik özelliklerden otomatik karar desteği üretmek olarak kodlandı.','Çalışma küçük AAA''da hızlı büyümeyi öngörmek için aort kesit seçimi, lokalizasyon ve multimodal füzyonu birleştirir.','{"AUC": "0.9964", "ACC": "0.9991", "SEN": "0.902", "F1": "0.9986"}','Yok','Yok','Yok','Yok',NULL,'Manuel ayrıntılı inceleme','underscores the urgent need for better predictors of aneurysm behavior. Consequently, accurately forecasting the AAA growth rate has become a central research priority, as it is crucial for surgical planning and personalized surveillance, with guidelines recommending intervention when growth exceeds 0.5 cm per 6 months (Ullery et al., 2018; Isselba','https://doi.org/10.3389/fphys.2025.1704428');
