INSERT INTO extracted_studies (ref_no,first_author,authors_full,year,title,venue,country,pathology,pathology_code,modality,dataset_name,dataset_access,patient_count,image_count,task,model,method_detail,summary,performance,ext_validation,radiologist_comparison,open_code,open_data,code_url,depth,limitations,doi_url) VALUES (152,'Tomihama R.T.','Tomihama R. T.; Camara J. R.; Kiang S. C.',2023,'Machine learning analysis of confounding variables of a convolutional neural network specific for abdominal aortic aneurysms','JVS-Vascular Science, 4',NULL,'Abdominal Aort Anevrizması/Diseksiyonu','AAA','Belirsiz',NULL,'Özel/tek merkez',400,31899,'infrarenal abdominal aort anevrizması taraması/sınıflandırması','VGG-16 tabanlı transfer öğrenmeli CNN','AAA''ya özgü CNN modeli VGG-16 taban mimarisi üzerine transfer öğrenme ile eğitilmiş; denge/dengesizlik, ekstra-abdominal kesitler, mural trombüs ve anevrizma boyutu gibi karıştırıcı değişkenlerin performansa etkisi incelenmiştir.','Çalışma, CTA''da infrarenal AAA saptayan VGG-16 tabanlı CNN''in karıştırıcı değişkenlere dayanıklılığını analiz eder.','{"AUC": "0.99", "ACC": "0.9833", "SEN": "0.987"}','Yok','Yok','Yok','Yok',NULL,'PDF tam metin','of this study. First, this is a retrospective single-center study with a limited number of subjects who had certain exclusion criteria (ruptured aneurysm, prior repair of an infrarenal AAA, and/or protocol errors [absence of IV contrast material, timing issues, etc]).','https://doi.org/10.1016/j.jvssci.2022.11.004');
